// ===== TopWorstSellers.js =====
import React, { useState, useEffect } from 'react';
import axios from 'axios';
import './TopWorstSellers.css';
import Optionbar from './Optionbar';
import {
    segmentOptions,
    locationOptions,
    seasonOptions,
    highlightOptions
} from './Icons/optionbarOptions';

// Helper: get Set of all option IDs
const makeSet = arr => new Set(arr.map(o => o.id));

const TopWorstSellers = () => {
    const [searchTerm, setSearchTerm] = useState('');
    const [sortOrder, setSortOrder]   = useState('top');
    const [items, setItems]           = useState([]);
    const [loading, setLoading]       = useState(true);
    const [error, setError]           = useState(null);

    // Controlled filters state
    const [filters, setFilters] = useState({
        segments:   makeSet(segmentOptions),
        highlights: makeSet(highlightOptions),
        seasons:    makeSet(seasonOptions),
        locations:  makeSet(locationOptions)
    });

    // Fetch sales on mount or filters change
    useEffect(() => {
        const fetchSales = async () => {
            setLoading(true);
            try {
                // fetch all, do client-side filtering
                const res = await axios.get('/api/sales', { withCredentials: true });
                const mapped = res.data.map(i => ({
                    name:         i.item_name,
                    count:        i.total_sold || i.sold_count,
                    categoryId:   i.id_category,
                    category:     i.category_name,
                    high_margin:  i.is_high_margin === 1,
                    trending:     i.is_trending === 1,
                    eco_friendly: i.eco_friendly === 'Yes' || i.eco_friendly === 1,
                    season:       i.season || 'Unknown'
                }));
                setItems(mapped);
            } catch (e) {
                console.error('Fetch sales failed:', e);
                setError('Kon verkoopcijfers niet laden');
            } finally {
                setLoading(false);
            }
        };
        fetchSales();
    }, []);

    if (loading) return <p>Loading…</p>;
    if (error)   return <p className="error">{error}</p>;

    // Apply filters client-side
    const filtered = items.filter(item =>
        filters.segments.has(item.categoryId) &&
        filters.highlights.has(item.high_margin ? 1 : 0) &&
        filters.seasons.has(seasonOptions.findIndex(o=>o.label===item.season)) &&
        filters.locations.has(item.categoryId) // adjust location grouping as needed
    );

    // Sort
    const sorted = [...filtered].sort((a,b) =>
        sortOrder === 'top' ? b.count - a.count : a.count - b.count
    );

    // Search
    const visible = sorted.filter(i =>
        i.name.toLowerCase().includes(searchTerm.toLowerCase())
    );

    return (
        <div className="top-worst-container">
            <div className="centre-content">
                <div className="segment-section">
                    <h2 className="section-title">Top & Worst</h2>
                </div>
                <div className="items-section">
                    {/* Header */}
                    <div className="list-header">
                        <div className="header-title">
                            <p>Top & Worst</p>
                            <h2 className="section-title">Menu-items</h2>
                        </div>
                        <div className="section-order">
                            <span className={`order-button ${sortOrder==='top'?'active':''}`} onClick={()=>setSortOrder('top')}>Top sellers ↑</span>
                            <span className={`order-button ${sortOrder==='worst'?'active':''}`} onClick={()=>setSortOrder('worst')}>Worst sellers ↓</span>
                        </div>
                        <div className="search-bar">
                            <input
                                type="text"
                                placeholder="Search"
                                value={searchTerm}
                                onChange={e=>setSearchTerm(e.target.value)}
                            />
                        </div>
                    </div>
                    {/* List */}
                    <ul className="items-list">
                        {visible.map((item, idx) => (
                            <li key={idx} className="item">
                                <span>{idx+1}. {item.name}</span>
                                <span className="item-count">{item.count} sold</span>
                            </li>
                        ))}
                    </ul>
                </div>
            </div>
            {/* Controlled sidebar */}
            <Optionbar filters={filters} onChange={setFilters} />
        </div>
    );
};

export default TopWorstSellers;
